// ======================================================================================
// DROPDOWN STYLES
// ======================================================================================

const dropdownStyles = StyleSheet.create({
  dropdown: {
    backgroundColor: 'rgba(255, 255, 255, 0.1)',
    borderRadius: 8,
    borderWidth: 1,
    borderColor: 'rgba(255, 255, 255, 0.2)',
