  const [tenseChosen, setTenseChosen] = useState<boolean>(false);

  // ======================================================================================
  // DATA FROM V3_FRENCHVERBDATA.JS - COMPREHENSIVE VERB SYSTEM
  // ======================================================================================

  const difficulties = [
    { 
      label: 'Beginner', 
      value: 'beginner',
