          {/* Selection Card - EXACT MATCH TO YOUR SCREENSHOT */}
          <Animated.View 
            style={[
              styles.selectionCard,
              { opacity: fadeAnim, transform: [{ translateY: slideAnim }] }
            ]}
          >
            {/* 1. Choose Difficulty */}
            {renderDropdown(
              '1. Choose Difficulty',
              'Select difficulty level...',
              selectedDifficulty,
              setSelectedDifficulty,
              difficulties,
              false,
              'difficulty',
              difficultyChosen
            )}

            {/* 2. Choose a French Verb */}
            {renderDropdown(
              '2. Choose a French Verb',
