}

function convertToNegativeEnglish(englishSentence: string, pronoun: string): string {
  // Handle different verb forms for negation
  let sentence = englishSentence.trim();

  // CRITICAL FIX: Handle malformed negations FIRST before processing normal patterns
  // Fix incorrectly placed "didn't" patterns
  if (sentence.includes("didn't (") || sentence.includes("don't (") || sentence.includes("doesn't (")) {
    // Fix "You didn't (informal) did" -> "You (informal) didn't do"
    sentence = sentence
      .replace(/You didn't \(informal\) did\/made/g, "You (informal) didn't do/make")
      .replace(/You didn't \(formal\/plural\) did\/made/g, "You (formal/plural) didn't do/make")
      .replace(/They didn't \(masculine\) did\/made/g, "They (masculine) didn't do/make")
      .replace(/They didn't \(feminine\) did\/made/g, "They (feminine) didn't do/make")
      .replace(/You don't \(informal\)/g, "You (informal) don't")
      .replace(/You don't \(formal\/plural\)/g, "You (formal/plural) don't")
      .replace(/They don't \(masculine\)/g, "They (masculine) don't")
      .replace(/They don't \(feminine\)/g, "They (feminine) don't");
  }

  // CRITICAL FIX: Handle "used to" constructions FIRST - they should NEVER use "don't"
  if (sentence.includes("used to don't") || sentence.includes("used to doesn't")) {
    return sentence.replace("used to don't", "didn't use to").replace("used to doesn't", "didn't use to");
  }

  // CRITICAL FIX: Prevent malformed contractions FIRST
  if (sentence.includes("doingn't") || sentence.includes("beingn't") || sentence.includes("goingn't") || 
      sentence.includes("sayingn't") || sentence.includes("gettingn't") || sentence.includes("feelingn't")) {
    sentence = sentence
      .replace(/doingn't/g, "not doing")
      .replace(/beingn't/g, "not being") 
      .replace(/goingn't/g, "not going")
      .replace(/sayingn't/g, "not saying")
      .replace(/gettingn't/g, "not getting")
      .replace(/feelingn't/g, "not feeling")
      .replace(/washingn't/g, "not washing")
      .replace(/wakingn't/g, "not waking");
    return sentence;
  }

  // CRITICAL FIX: Prevent "had hadn't" double negations FIRST
  if (sentence.includes("had hadn't")) {
    return sentence.replace("had hadn't", "hadn't had");
  }

  // CRITICAL: Fix any existing "will don't" double negations FIRST
  if (sentence.includes("will don't")) {
    return sentence.replace("will don't", "will not");
  }

  // Handle predefined negative contexts - don't apply double negation
  if (sentence.includes(" no ") || sentence.includes("nothing") || sentence.includes("never") || 
      sentence.includes("nowhere") || sentence.includes("nobody") || sentence.includes("n't")) {
    return sentence; // Already negative, don't modify
  }

  // CRITICAL: Handle ALL future tense cases FIRST to prevent "will don't" constructions
  if (sentence.includes(" will ")) {
    return sentence.replace(" will ", " will not ");
  }

  // For simple "to be" forms without trailing space (e.g., "I am", "He is")
  if (sentence.endsWith(" am")) {
    return sentence.replace(" am", " am not");
  }
  if (sentence.endsWith(" is")) {
    return sentence.replace(" is", " is not");
  }
  if (sentence.endsWith(" are")) {
    return sentence.replace(" are", " are not");
  }

  // For "to be" verbs with trailing content
  if (sentence.includes(" am ") || sentence.includes(" is ") || sentence.includes(" are ")) {
    return sentence
      .replace(" am ", " am not ")
      .replace(" is ", " is not ")
      .replace(" are ", " are not ");
  }

  // CRITICAL FIX: Handle "was/were" past tense of "to be" - NEVER use "don't/doesn't"
  if (sentence.endsWith(" was")) {
    return sentence.replace(" was", " wasn't");
  }
  if (sentence.endsWith(" were")) {
    return sentence.replace(" were", " weren't");
  }
  if (sentence.includes(" was ")) {
    return sentence.replace(" was ", " wasn't ");
  }
  if (sentence.includes(" were ")) {
    return sentence.replace(" were ", " weren't ");
  }

  // For compound tenses with "have/has" auxiliary verbs (perfect tenses)
  if (sentence.includes(" have ") || sentence.includes(" has ")) {
    return sentence
      .replace(" have ", " haven't ")
      .replace(" has ", " hasn't ");
  }

  // For simple "to have" forms without trailing space
  if (sentence.endsWith(" have")) {
    return sentence.replace(" have", " don't have");
  }
  if (sentence.endsWith(" has")) {
    return sentence.replace(" has", " doesn't have");
  }

  // For past tense verbs (ended in -ed or irregular) OR present forms in past contexts
  // IMPORTANT: Handle "had" as main verb (not auxiliary) by checking for main verb usage
  if (sentence.includes(" went") || sentence.includes(" did") || sentence.includes(" made") || 
      sentence.includes(" saw") || sentence.includes(" said") ||
      sentence.includes(" ate") || sentence.includes(" drank") || sentence.includes(" walked") ||
      sentence.includes(" talked") || sentence.includes(" worked") || sentence.includes(" lived") ||
      sentence.includes(" goes") || sentence.includes(" says") || sentence.includes(" does") ||
      sentence.includes(" makes") || sentence.includes(" sees") || sentence.includes(" knows") ||
      sentence.includes(" wants") || sentence.includes(" comes") || sentence.includes(" feels") ||
      sentence.includes(" did/made") || sentence.includes(" does/makes")) {
    const words = sentence.split(" ");
    if (words.length >= 2) {
      const subject = words[0];
      const verb = words[1];
      return sentence.replace(` ${verb}`, ` didn't ${getBaseVerb(verb)}`);
    }
  }

  // For auxiliary verbs in compound tenses (e.g., "He had eaten" -> "He hadn't eaten" for pluperfect)
  // Only apply this AFTER checking for main verb usage above
  // CRITICAL FIX: Handle "had" as main verb first (most common case)
  if (sentence.includes(" had") && !sentence.includes("didn't") && !sentence.includes("hadn't")) {
    return sentence.replace(" had", " didn't have");
  }

  // Check if "had" is auxiliary (followed by past participle) vs main verb
  if (sentence.includes(" had ") && !sentence.includes("didn't") && !sentence.includes("hadn't")) {
    // Look for common past participles after "had" to confirm auxiliary usage
    const auxiliaryPatterns = [" had been", " had done", " had made", " had gone", " had seen", " had said", " had eaten", " had taken", " had given", " had worked", " had studied", " had lived", " had felt", " had gotten", " had woken", " had come", " had known", " had wanted"];
    const isAuxiliary = auxiliaryPatterns.some(pattern => sentence.includes(pattern));

    if (isAuxiliary) {
      return sentence.replace(" had ", " hadn't ");
    } else {
      // Handle "had" as main verb (e.g., "I had breakfast" -> "I didn't have breakfast")  
      return sentence.replace(" had ", " didn't have ");
    }
  }

  // Handle remaining "used to" constructions for proper negation
  if (sentence.includes("used to ") && !sentence.includes("didn't") && !sentence.includes("never")) {
    // Apply negation correctly for "used to" - use "didn't use to"
    return sentence.replace("used to ", "didn't use to ");
  }

  // For sentences ending with a period (past tense statements)
  if (sentence.endsWith(".")) {
    const words = sentence.slice(0, -1).split(" "); // Remove period and split
    if (words.length >= 2) {
      const subject = words[0];
      const verb = words[1];

      // Check if it's a past tense verb by looking for common patterns
      if (verb.endsWith("ed") || ["had", "went", "did", "made", "saw", "said", "ate", "drank", "came", "took", "got", "knew", "thought", "felt"].includes(verb)) {
        const baseVerb = getBaseVerb(verb);
        return sentence.replace(` ${verb}`, ` didn't ${baseVerb}`);
      }
    }
  }

  // For future tense with "will" - handle all cases first to prevent "will don't" constructions
  if (sentence.includes(" will have")) {
    return sentence.replace(" will have", " will not have");
  }
  if (sentence.includes(" will be")) {
    return sentence.replace(" will be", " will not be");
  }
  if (sentence.includes(" will do")) {
    return sentence.replace(" will do", " will not do");
  }
  if (sentence.includes(" will make")) {
    return sentence.replace(" will make", " will not make");
  }
  if (sentence.includes(" will go")) {
    return sentence.replace(" will go", " will not go");
  }
  if (sentence.includes(" will see")) {
    return sentence.replace(" will see", " will not see");
  }
  if (sentence.includes(" will say")) {
    return sentence.replace(" will say", " will not say");
  }
  if (sentence.includes(" will know")) {
    return sentence.replace(" will know", " will not know");
  }
  if (sentence.includes(" will want")) {
    return sentence.replace(" will want", " will not want");
  }
  if (sentence.includes(" will come")) {
    return sentence.replace(" will come", " will not come");
  }
  if (sentence.includes(" will get")) {
    return sentence.replace(" will get", " will not get");
  }
  if (sentence.includes(" will feel")) {
    return sentence.replace(" will feel", " will not feel");
  }
  if (sentence.includes(" will wash")) {
    return sentence.replace(" will wash", " will not wash");
  }
  if (sentence.includes(" will wake")) {
    return sentence.replace(" will wake", " will not wake");
  }
  // General "will" replacement for any remaining cases
  if (sentence.includes(" will ")) {
    return sentence.replace(" will ", " will not ");
  }

  // For other verbs - add "don't" or "doesn't" ONLY if not already handled by will/future cases
  if (!sentence.includes("will") && !sentence.includes("will not")) {
    const words = sentence.split(" ");
    if (words.length >= 2) {
      const subject = words[0];
      const verb = words[1];

      if (subject === "He" || subject === "She") {
        return sentence.replace(` ${verb}`, ` doesn't ${verb.toLowerCase()}`);
      } else {
        return sentence.replace(` ${verb}`, ` don't ${verb.toLowerCase()}`);
      }
    }
  }

  return sentence; // fallback
}

// Helper function to get base verb form from past tense
function getBaseVerb(pastVerb: string): string {
  const irregularVerbs: { [key: string]: string } = {
    'went': 'go',
    'did': 'do',
    'made': 'make',
    'had': 'have',
    'saw': 'see',
    'said': 'say',
    'came': 'come',
    'took': 'take',
    'got': 'get',
    'knew': 'know',
    'thought': 'think',
    'felt': 'feel',
    'ate': 'eat',
    'drank': 'drink',
    'was': 'be',
    'were': 'be',
    // Present forms that need base conversion for past negation
    'goes': 'go',
    'says': 'say',
    'does': 'do',
    'makes': 'make',
    'sees': 'see',
    'knows': 'know',
    'wants': 'want',
    'comes': 'come',
    'feels': 'feel',
    'did/made': 'do/make',
    'does/makes': 'do/make'
  };

  if (irregularVerbs[pastVerb]) {
    return irregularVerbs[pastVerb];
  }

  // For regular verbs, remove -ed ending
  if (pastVerb.endsWith('ed')) {
    let base = pastVerb.slice(0, -2);
    // Handle doubled consonants (e.g., "walked" -> "walk", "stopped" -> "stop")
    return base;
  }

  return pastVerb; // fallback
}

// Helper function to remove ONLY progressive verb forms while preserving context
function removeProgressiveFormsOnly(sentence: string): string {
  if (!sentence.includes(' / ')) {
    return sentence;
  }

  // TARGETED APPROACH: Extract context from progressive form and merge with simple form
  // Examples:
  // "I say / I am saying hello." → "I say hello."
  // "You had / You were having dinner." → "You had dinner."
  // "I have / I am having a car." → "I have a car."

  // Split on " / " to get the simple and progressive parts
  const parts = sentence.split(' / ');
  if (parts.length !== 2) {
    return sentence; // Safety fallback
  }

  const simplePart = parts[0].trim(); // "I have"
  const progressivePart = parts[1].trim(); // "I am having a car."

  // Extract context after the progressive verb using more flexible regex
  // Match: PRONOUN + AUX + (not)? + VERB_ING + CONTEXT
  // Updated to handle patterns like "I am having a car" not just "I am saying hello"
  const contextPattern = /^[^.]*?\b(?:am|is|are|was|were|had\s+been)\s+(?:not\s+)?(?:\w+ing)\b(.*)$/;
  const contextMatch = progressivePart.match(contextPattern);

  if (contextMatch && contextMatch[1]) {
    const context = contextMatch[1].trim(); // " a car."
    // Combine simple form with extracted context
    return simplePart + (context ? ' ' + context : '');
  }

  // Fallback: more direct approach for cases like "I am having a car"
  // Remove progressive auxiliary and convert verb to simple form
  const directPattern = /^(.*?)\s+(?:am|is|are|was|were)\s+(?:not\s+)?(\w+ing)(.*)$/;
  const directMatch = progressivePart.match(directPattern);

  if (directMatch) {
    const pronoun = directMatch[1].trim(); // "I"
    const verbIng = directMatch[2]; // "having"
    const context = directMatch[3].trim(); // " a car."

    // Convert ing verb to simple form (having → have, doing → do, etc.)
    const simpleVerb = convertIngToSimple(verbIng);
    return pronoun + ' ' + simpleVerb + (context ? ' ' + context : '');
  }

  // If no pattern matches, return just the simple part
  return simplePart + (progressivePart.endsWith('.') ? '.' : '');
}

// Helper function to convert -ing verbs to simple forms
function convertIngToSimple(verbIng: string): string {
  // Common -ing to simple form conversions
  const conversions: Record<string, string> = {
    'having': 'have',
    'doing': 'do',
    'making': 'make',
    'saying': 'say',
    'going': 'go',
    'being': 'am', // Special case for "being"
    'feeling': 'feel',
    'seeing': 'see',
    'knowing': 'know',
    'wanting': 'want',
    'coming': 'come',
    'taking': 'take',
    'getting': 'get',
    'waking': 'wake',
    'washing': 'wash',
    'dressing': 'dress',
    'leaving': 'leave',
    'calling': 'call'
  };

  return conversions[verbIng] || verbIng.replace(/ing$/, '');
}

