    }
  }

  // Special handling for "avoir" with different pronouns  
  if (verb === 'avoir') {
    if (tense === 'present') {
      if (pronoun === 'il' || pronoun === 'elle') return `${englishPronoun} has`;
      if (pronoun === 'je' || pronoun === 'tu' || pronoun === 'vous' || pronoun === 'nous' || pronoun === 'ils' || pronoun === 'elles') return `${englishPronoun} have`;
      return `${englishPronoun} have`;
    }
  }

  // Handle Present Progressive (Présent Progressif) 
  if (tense === 'présent_progressif') {
    const baseVerb = verbData[tense as keyof typeof verbData] || verbData.présent_progressif;

    if (pronoun === 'je') return `I am ${baseVerb}`;
    if (pronoun === 'tu') return `You are ${baseVerb}`;
    if (pronoun === 'il') return `He is ${baseVerb}`;
    if (pronoun === 'elle') return `She is ${baseVerb}`;
    if (pronoun === 'nous') return `We are ${baseVerb}`;
    if (pronoun === 'vous') return `You are ${baseVerb}`;
    if (pronoun === 'ils') return `They are ${baseVerb}`;
    if (pronoun === 'elles') return `They are ${baseVerb}`;

    return `${englishPronoun} are ${baseVerb}`;
  }

  // Handle Plus-que-parfait
  if (tense === 'plus_que_parfait') {
    const baseVerb = verbData[tense as keyof typeof verbData] || verbData.plus_que_parfait;
    return `${englishPronoun} ${baseVerb}`;
  }

  // Handle Imparfait
  if (tense === 'imparfait') {
    const baseVerb = verbData[tense as keyof typeof verbData] || verbData.imparfait;
    return `${englishPronoun} ${baseVerb}`;
  }

  // General conjugation logic for present tense
  if (tense === 'present') {
    const baseVerb = verbData[tense as keyof typeof verbData] || verbData.present;

    // Third person singular (he/she) - add 's' where appropriate
    if (pronoun === 'il' || pronoun === 'elle') {
      if (verb === 'dire') return `${englishPronoun} says`;
      if (verb === 'faire') return `${englishPronoun} does/makes`;
      if (verb === 'aller') return `${englishPronoun} goes`;
      if (verb === 'voir') return `${englishPronoun} sees`;
      if (verb === 'savoir') return `${englishPronoun} knows`;
      if (verb === 'pouvoir') return `${englishPronoun} can`;
      if (verb === 'vouloir') return `${englishPronoun} wants`;
      if (verb === 'venir') return `${englishPronoun} comes`;
      if (verb === 'prendre') return `${englishPronoun} takes`;
      if (verb === 'se lever') return `${englishPronoun} gets up`;
      if (verb === 's\'appeler') return `${englishPronoun} is called`;
      if (verb === 'se sentir') return `${englishPronoun} feels`;
      if (verb === 'se laver') return `${englishPronoun} washes`;
      if (verb === 'se réveiller') return `${englishPronoun} wakes up`;
      if (verb === 's\'habiller') return `${englishPronoun} gets dressed`;
    }

    // All other persons use base verb form
    return `${englishPronoun} ${baseVerb}`;
  }

  // For other tenses, use the base verb form
  const englishVerb = verbData[tense as keyof typeof verbData] || verbData.present;
  return `${englishPronoun} ${englishVerb}`;
}

// Helper function to convert generic "They" to gender-specific pronouns for all courses
function convertToGenderSpecificPronouns(englishQuestion: string, difficulty?: string): string {
  // Apply gender specification for ALL difficulty levels
  // But ONLY if the question doesn't already contain gender notations

  // Check if question already contains gender/pronoun clarifications
  if (englishQuestion.includes('(male/mixed)') || 
      englishQuestion.includes('(female)') || 
      englishQuestion.includes('(formal/plural)') ||
      englishQuestion.includes('(informal)') ||
      englishQuestion.includes('(plural)')) {
    return englishQuestion; // Return as-is if already contains gender notation
  }

  // Apply gender-specific replacements for "They" patterns ONLY if not already present
  return englishQuestion
    .replace(/They have/g, 'They have (male/mixed)')
    .replace(/They are/g, 'They are (male/mixed)')
    .replace(/They do/g, 'They do (male/mixed)')
    .replace(/They make/g, 'They make (male/mixed)')
    .replace(/They go/g, 'They go (male/mixed)')
    .replace(/They see/g, 'They see (male/mixed)')
    .replace(/They say/g, 'They say (male/mixed)')
    .replace(/They know/g, 'They know (male/mixed)')
    .replace(/They can/g, 'They can (male/mixed)')
    .replace(/They want/g, 'They want (male/mixed)')
    .replace(/They come/g, 'They come (male/mixed)')
    .replace(/They take/g, 'They take (male/mixed)')
    .replace(/They get up/g, 'They get up (male/mixed)')
    .replace(/They are called/g, 'They are called (male/mixed)')
    .replace(/They feel/g, 'They feel (male/mixed)')
    .replace(/They wash/g, 'They wash (male/mixed)')
    .replace(/They wake up/g, 'They wake up (male/mixed)')
    .replace(/They call/g, 'They call (male/mixed)')
    .replace(/They dress/g, 'They dress (male/mixed)')
    .replace(/They don't/g, 'They don\'t (male/mixed)')
    .replace(/They used to/g, 'They used to (male/mixed)')
    .replace(/They were/g, 'They were (male/mixed)')
    .replace(/They would/g, 'They would (male/mixed)')
    .replace(/They did/g, 'They did (male/mixed)')
    .replace(/They went/g, 'They went (male/mixed)')
    .replace(/They made/g, 'They made (male/mixed)')
    .replace(/They saw/g, 'They saw (male/mixed)')
    .replace(/They said/g, 'They said (male/mixed)')
    .replace(/They knew/g, 'They knew (male/mixed)')
    .replace(/They could/g, 'They could (male/mixed)')
    .replace(/They wanted/g, 'They wanted (male/mixed)')
    .replace(/They came/g, 'They came (male/mixed)')
    .replace(/They took/g, 'They took (male/mixed)')
    .replace(/They washed/g, 'They washed (male/mixed)')
    .replace(/They woke/g, 'They woke (male/mixed)')
    .replace(/They called/g, 'They called (male/mixed)')
    .replace(/They dressed/g, 'They dressed (male/mixed)')
    .replace(/They will/g, 'They will (male/mixed)')
    .replace(/They would/g, 'They would (male/mixed)');
}

export function generateInternalQuiz(verb: string, tense: string, difficulty?: string, isExam?: boolean): GeneratedQuiz {
