    } else {
      console.log(`⚠️ No verified beginner pronoun questions found for ${verb} - ${mappedTense}, falling back to generated`);
    }
  }

  // Use verified novice questions for Novice difficulty
  if (difficulty === 'Novice' && ['être', 'avoir', 'faire', 'aller'].includes(verb)) {
    // Map frontend tenses to our verified question tenses
    let mappedTense = tense.toLowerCase();
    if (mappedTense === 'présent' || mappedTense === 'present') mappedTense = 'present';
    if (mappedTense === 'passé simple' || mappedTense === 'passé composé') mappedTense = 'passé_composé'; // Novice uses passé composé instead
    if (mappedTense === 'futur simple') mappedTense = 'futur_simple';

    console.log(`🎓 Using corrected verified novice questions for ${verb} - ${mappedTense} (original: ${tense})`);

    const noviceQuestions = getRandomNoviceQuestions(verb, mappedTense, 20);

    if (noviceQuestions.length > 0) {
      console.log(`✅ Found ${noviceQuestions.length} corrected verified novice questions`);
      const convertedQuestions = convertNoviceToQuizFormat(noviceQuestions);
      return {
        questions: convertedQuestions
      };
    } else {
      console.log(`⚠️ No corrected verified questions found for ${verb} - ${mappedTense}, falling back to generated`);
    }
  }

  // Use verified Elementary questions for Elementary difficulty
  if (difficulty === 'Elementary' && ['dire', 'voir', 'savoir', 'vouloir', 'venir', 'pouvoir', 'besoin'].includes(verb)) {
    console.log(`🎓 Using verified Elementary questions for ${verb} - ${tense}`);

    let elementaryQuestions: ElementaryQuizQuestion[] = [];

    // Handle different tenses for Elementary level
    if (tense.toLowerCase() === 'présent' || tense.toLowerCase() === 'present') {
      elementaryQuestions = getRandomElementaryPresentQuestions(verb, 20);
      console.log(`✅ Found ${elementaryQuestions.length} Elementary present questions for ${verb}`);
    } else if (tense.toLowerCase() === 'passé composé' || tense.toLowerCase() === 'passé simple') {
      elementaryQuestions = getRandomElementaryPasseComposeQuestions(verb, 20);
      console.log(`✅ Found ${elementaryQuestions.length} Elementary passé composé questions for ${verb}`);
    } else if (tense.toLowerCase() === 'futur simple' || tense.toLowerCase() === 'future') {
      elementaryQuestions = getRandomElementaryFutureSimpleQuestions(verb, 20);
      console.log(`✅ Found ${elementaryQuestions.length} Elementary future simple questions for ${verb}`);
    }

    if (elementaryQuestions.length > 0) {
      return {
        questions: elementaryQuestions.map(q => ({
          question: q.question,
          hint: q.hint,
          answerOptions: q.answerOptions
        }))
      };
    } else {
      console.log(`⚠️ No verified Elementary questions found for ${verb} - ${tense}, falling back to generated`);
    }
  }

  // Normalize tense names - map frontend tense names to backend tense keys
  let normalizedTense = tense.toLowerCase();

  // Handle specific tense mappings BEFORE general replacements
  if (normalizedTense === 'présent progressif' || normalizedTense === 'present progressive') {
    normalizedTense = 'présent_progressif';
  } else {
    normalizedTense = normalizedTense
      .replace('présent', 'present')
      .replace('passé composé', 'passé_composé')
      .replace('passé simple', 'passé_simple')
      .replace('plus-que-parfait', 'plus_que_parfait')
      .replace('imparfait', 'imparfait')
      .replace('conditionnel', 'conditionnel')
      .replace('futur simple', 'futur_simple')
      .replace('futur proche', 'futur_proche')
      .replace(/\s+/g, '_');
  }

  console.log(`🔧 Tense normalization: "${tense}" → "${normalizedTense}"`);

  const verbData = VERB_CONJUGATIONS[verb as keyof typeof VERB_CONJUGATIONS];
  const contexts = QUESTION_CONTEXTS[verb as keyof typeof QUESTION_CONTEXTS] || [];

  console.log(`🔧 Available verbs: ${Object.keys(VERB_CONJUGATIONS)}`);
  console.log(`🔧 Available tenses for ${verb}: ${verbData ? Object.keys(verbData) : 'none'}`);

  if (!verbData || !contexts.length) {
    throw new Error(`No internal data available for ${verb} - ${tense}`);
  }

  const tenseData = verbData[normalizedTense as keyof typeof verbData] as any;
  if (!tenseData) {
    console.log(`🔧 Tense lookup failed: "${normalizedTense}" not found in ${JSON.stringify(Object.keys(verbData))}`);
    throw new Error(`Tense ${normalizedTense} not available for ${verb}`);
  }

  const questions = [];
  const pronouns = ['je', 'tu', 'il', 'elle', 'nous', 'vous', 'ils', 'elles'];

  // Handle Novice mode - use contexts but with simple processing
  if (difficulty === 'Novice') {
    console.log('🔧 Generating Novice mode quiz (using contexts with simple processing)');

    // Ensure exactly 30% of questions are negative (6 out of 20)
    const totalQuestions = 20;
    const negativeQuestionCount = Math.floor(totalQuestions * 0.3); // 6 questions
    const negativeIndices = new Set<number>();

    // Randomly select which questions will be negative
    while (negativeIndices.size < negativeQuestionCount) {
      negativeIndices.add(Math.floor(Math.random() * totalQuestions));
    }

    for (let i = 0; i < 20; i++) {
      const context = contexts[i % contexts.length];
      const pronoun = (context as any).pronoun || pronouns[i % pronouns.length];
      const conjugation = tenseData[pronoun];

      if (!conjugation) continue;

      // Determine if this question should be negative (30% chance)
      const shouldBeNegative = negativeIndices.has(i);

      // Use context but remove progressive forms for simplicity
      let englishQuestion = fixEnglishGrammar(context.en);
      englishQuestion = removeProgressiveFormsOnly(englishQuestion); // Apply to Novice too
      let correctAnswer;

      if (shouldBeNegative) {
        // Convert to negative using the same logic as non-Novice modes
        if ((context as any).negative) {
          // Context is already negative, use as-is
          englishQuestion = fixEnglishGrammar(context.en);
          englishQuestion = removeProgressiveFormsOnly(englishQuestion);
          correctAnswer = buildNegativeFrench(pronoun, conjugation, context.fr_context, normalizedTense, verb);
        } else {
          // Convert positive context to negative
          englishQuestion = convertToNegativeEnglish(fixEnglishGrammar(context.en), pronoun);
          englishQuestion = removeProgressiveFormsOnly(englishQuestion);
          correctAnswer = buildNegativeFrench(pronoun, conjugation, context.fr_context, normalizedTense, verb);
        }
      } else {
        // For positive contexts - ensure consistency  
        if ((context as any).negative) {
          // Skip negative contexts when we want positive questions
          continue;
        }
        correctAnswer = applyContractions(pronoun, conjugation);
        if (context.fr_context) {
          correctAnswer += ` ${context.fr_context}`;
        }
      }

      // Create wrong answer options - use enhanced distractors for exams, pronouns for regular quizzes
      let wrongAnswers: string[];

      if (isExam) {
        // Use enhanced exam distractors (mixed verbs from different difficulty levels)
        const distractors = generateExamDistractors(conjugation, verb, normalizedTense, pronoun);
        wrongAnswers = distractors.slice(0, 3).map((form, index) => {
          // CRITICAL FIX: Match the polarity of the correct answer for exams too
          if (shouldBeNegative) {
            // If correct answer is negative, wrong answers should be positive  
            return applyContractions(pronoun, form) + (context.fr_context ? ` ${context.fr_context}` : "");
          } else {
            // If correct answer is positive, wrong answers should be mixed
            const makeDistractorNegative = index === 0; // Only first distractor is negative
            if (makeDistractorNegative) {
              return buildNegativeFrench(pronoun, form, context.fr_context, normalizedTense, verb);
            } else {
              return applyContractions(pronoun, form) + (context.fr_context ? ` ${context.fr_context}` : "");
            }
          }
        });
      } else {
        // Regular unit quiz - use same verb with different pronouns
        wrongAnswers = pronouns
          .filter(p => p !== pronoun)
          .slice(0, 3)
          .map((wrongPronoun, index) => {
            const wrongConjugation = tenseData[wrongPronoun];
            // CRITICAL FIX: Match the polarity of the correct answer
            if (shouldBeNegative) {
              // If correct answer is negative, wrong answers should be positive  
              return applyContractions(wrongPronoun, wrongConjugation) + (context.fr_context ? ` ${context.fr_context}` : "");
            } else {
              // If correct answer is positive, wrong answers should be mixed
              const makeDistractorNegative = index === 0; // Only first distractor is negative
              if (makeDistractorNegative) {
                return buildNegativeFrench(wrongPronoun, wrongConjugation, context.fr_context, normalizedTense, verb);
              } else {
                return applyContractions(wrongPronoun, wrongConjugation) + (context.fr_context ? ` ${context.fr_context}` : "");
              }
            }
          });
      }

      // Shuffle answers
      const allAnswers = [correctAnswer, ...wrongAnswers];
      const shuffledAnswers = allAnswers.sort(() => Math.random() - 0.5);

      questions.push({
        question: englishQuestion, // Use context-based questions for Novice too
        hint: `Think about the correct conjugation of "${verb}" for "${pronoun}"`,
        answerOptions: shuffledAnswers.map(answer => ({
          text: answer,
          isCorrect: answer === correctAnswer,
          rationale: answer === correctAnswer 
            ? `Correct! "${pronoun}" takes the conjugation "${conjugation}"`
            : `Incorrect. The correct answer is "${correctAnswer}"`
        }))
      });
    }

    return { questions };
  }

  // Generate 20 questions by cycling through contexts and pronouns
  // Ensure exactly 30% of questions are negative (6 out of 20)
  const totalQuestions = 20;
  const negativeQuestionCount = Math.floor(totalQuestions * 0.3); // 6 questions
  const negativeIndices = new Set<number>();

  // Randomly select which questions will be negative
  while (negativeIndices.size < negativeQuestionCount) {
    negativeIndices.add(Math.floor(Math.random() * totalQuestions));
  }

  for (let i = 0; i < 20; i++) {
    const context = contexts[i % contexts.length];

    // Use specified pronoun from context, or cycle through pronouns
    const pronoun = (context as any).pronoun || pronouns[i % pronouns.length];
    const correctForm = tenseData[pronoun];

    if (!correctForm) continue;

    // Determine if this question should be negative (30% chance)
    const shouldBeNegative = negativeIndices.has(i);

    // Build correct answer with proper French contractions
    let correctAnswer;

    if (shouldBeNegative) {
      // If context is already marked as negative, use its French negation logic
      if ((context as any).negative) {
        // Use predefined negative French context
        correctAnswer = buildNegativeFrench(pronoun, correctForm, context.fr_context, normalizedTense, verb);
      } else {
        // Convert positive context to negative French
        correctAnswer = buildNegativeFrench(pronoun, correctForm, context.fr_context, normalizedTense, verb);
      }
    } else {
      // For positive questions, only use positive contexts (ignore predefined negatives)
      if (!(context as any).negative) {
        correctAnswer = applyContractions(pronoun, correctForm);
        if (context.fr_context) {
          correctAnswer += ` ${context.fr_context}`;
        }
      } else {
        // Convert predefined negative to positive
        correctAnswer = applyContractions(pronoun, correctForm);
        if (context.fr_context && !context.fr_context.startsWith('pas')) {
          correctAnswer += ` ${context.fr_context}`;
        }
      }
    }

    // Generate distractors with proper French grammar
    const wrongAnswers = [];

    // Generate distractors using correct pronoun but wrong conjugations
    // Use enhanced exam distractors for final exams, regular distractors for unit quizzes
    const distractors = isExam 
      ? generateExamDistractors(correctForm, verb, normalizedTense, pronoun)
      : generateDistractors(correctForm, verb, normalizedTense, pronoun);
    distractors.slice(0, 3).forEach((form, index) => {
      let wrong;

      // CRITICAL FIX: Match the polarity of the correct answer for all paths
      if (shouldBeNegative) {
        // If correct answer is negative, wrong answers should be positive  
        wrong = applyContractions(pronoun, form);
        if (context.fr_context && !(context as any).negative) {
          wrong += ` ${context.fr_context}`;
        }
      } else {
        // If correct answer is positive, wrong answers should be mixed
        const makeDistractorNegative = index === 0; // Only first distractor is negative
        if (makeDistractorNegative) {
          wrong = buildNegativeFrench(pronoun, form, context.fr_context, normalizedTense, verb);
        } else {
          wrong = applyContractions(pronoun, form);
          if (context.fr_context && !(context as any).negative) {
            wrong += ` ${context.fr_context}`;
          }
        }
      }
      wrongAnswers.push(wrong);
    });

    // Ensure we have exactly 4 options by generating proper French fallback answers
    while (wrongAnswers.length < 3) {
      // Generate proper French wrong answers as fallbacks instead of placeholder text
      const fallbackPronouns = ['je', 'tu', 'il', 'elle', 'nous', 'vous', 'ils', 'elles'];
      const fallbackPronoun = fallbackPronouns[wrongAnswers.length % fallbackPronouns.length];
      const fallbackConjugation = tenseData[fallbackPronoun] || "manque";
      const fallbackAnswer = applyContractions(fallbackPronoun, fallbackConjugation);
      wrongAnswers.push(fallbackAnswer);
    }

    const allAnswers = [
      { text: correctAnswer, rationale: `Correct conjugation of ${verb} for ${pronoun} in ${tense}.`, isCorrect: true },
      { text: wrongAnswers[0], rationale: `Incorrect conjugation for ${pronoun}.`, isCorrect: false },
      { text: wrongAnswers[1], rationale: `Wrong tense or wrong pronoun conjugation.`, isCorrect: false },
      { text: wrongAnswers[2], rationale: `This uses an incorrect form of ${verb}.`, isCorrect: false }
    ];

    // Shuffle answers
    const shuffledAnswers = allAnswers.sort(() => Math.random() - 0.5);

    // Convert English to proper tense based on French tense
    let englishQuestion = fixEnglishGrammar(context.en);

    // CRITICAL: Remove progressive forms for ALL tenses in non-advanced levels
    // Only Advanced level should show dual forms like "I eat / I am eating"
    // All other levels should be simple: "I eat lunch" (not "I eat / I am eating lunch")
    if (difficulty !== 'Advanced') {
      englishQuestion = removeProgressiveFormsOnly(englishQuestion);
    }

    // CRITICAL: Apply tense conversion FIRST, then handle negation
    if (normalizedTense === 'futur_simple') {
      // For future tense: convert present to future first, BEFORE any negation logic
      englishQuestion = convertTenseBeforeNegation(englishQuestion, 'futur_simple', pronoun);
    }

    // Handle negation properly - respect predefined negatives or apply new negation
    if (shouldBeNegative) {
      // If context is already negative, use it as-is; otherwise convert to negative
      if ((context as any).negative) {
        englishQuestion = fixEnglishGrammar(context.en); // Keep predefined negatives
        // CRITICAL: Apply progressive form removal for negative contexts too
        if (difficulty !== 'Advanced') {
          englishQuestion = removeProgressiveFormsOnly(englishQuestion);
        }
      } else {
        // For future tense, simply replace "will" with "will not" - NO other negation logic
        if (normalizedTense === 'futur_simple') {
          englishQuestion = englishQuestion.replace(/ will /g, " will not ");
        } else {
          // For other tenses, apply negation to original context (before tense conversion)
          englishQuestion = convertToNegativeEnglish(fixEnglishGrammar(context.en), pronoun);
          // CRITICAL: Apply progressive form removal for negative contexts too
          if (difficulty !== 'Advanced') {
            englishQuestion = removeProgressiveFormsOnly(englishQuestion);
          }
        }

        // CRITICAL: Final cleanup of any grammar issues that slipped through
        englishQuestion = englishQuestion
          .replace(/will don't/g, "will not")
          .replace(/will doesn't/g, "will not")
          .replace(/used to don't/g, "didn't use to")
          .replace(/used to doesn't/g, "didn't use to")
          .replace(/doingn't/g, "not doing")
          .replace(/beingn't/g, "not being")
          .replace(/goingn't/g, "not going")
          .replace(/gettingn't/g, "not getting")
          .replace(/sayingn't/g, "not saying")
          .replace(/feelingn't/g, "not feeling")
          .replace(/had hadn't/g, "hadn't had")
          .replace(/will am/g, "will be")
          .replace(/will is/g, "will be")
          .replace(/will are/g, "will be")
          .replace(/will not am/g, "will not be")
          .replace(/will not is/g, "will not be")
          .replace(/will not are/g, "will not be");
      }
    } else {
      // For positive questions, only process if context is NOT already negative
      if (!(context as any).negative) {
        englishQuestion = context.en; // Use as-is for positive contexts
        // CRITICAL: Apply progressive form removal again for positive contexts
        if (difficulty !== 'Advanced') {
          englishQuestion = removeProgressiveFormsOnly(englishQuestion);
        }
      } else {
        // Convert predefined negative to positive by removing negation words
        englishQuestion = englishQuestion
          .replace("don't ", "")
          .replace("doesn't ", "")
          .replace("can't ", "can ")
          .replace(" not", "")
          .replace("I am not", "I am")
          .replace("He is not", "He is") 
          .replace("She is not", "She is")
          .replace("We are not", "We are")
          .replace("You are not", "You are")
          .replace("They are not", "They are");
      }

      // CRITICAL: Apply same cleanup for positive future tense questions
      if (normalizedTense === 'futur_simple') {
        englishQuestion = englishQuestion.replace(/will am/g, "will be");
        englishQuestion = englishQuestion.replace(/will is/g, "will be");
        englishQuestion = englishQuestion.replace(/will are/g, "will be");
      }
    }

    if (normalizedTense === 'passé_composé') {
      // Passé composé = completed action ("I ate" / "I have eaten")
      englishQuestion = englishQuestion
        .replace(/I have/g, 'I had')
        .replace(/You have/g, 'You had') 
        .replace(/He has/g, 'He had')
        .replace(/She has/g, 'She had')
        .replace(/We have/g, 'We had')
        .replace(/You \(plural\) have/g, 'You (plural) had')
        .replace(/They have/g, 'They had')
