                  <strong className="text-yellow-300">French Verb Master Version 1</strong> focuses on building a solid foundation with Beginner through Intermediate levels.
                </p>
              </div>

              <button
                onClick={() => setShowAdvancedLockedModal(false)}
                className="w-full p-4 bg-gradient-to-r from-purple-600 to-blue-600 hover:from-purple-500 hover:to-blue-500 text-white font-semibold rounded-xl transition-colors"
              >
                Got It! 👍
              </button>
            </div>
          </div>
        )}

        {/* Reflexive Verb Explanation Modal */}
        {showReflexiveModal && (
          <div className="fixed inset-0 bg-black/60 backdrop-blur-sm flex items-center justify-center z-50">
            <div className="bg-white/10 backdrop-blur-lg border border-white/20 rounded-2xl p-8 max-w-lg w-full mx-4">
              <div className="text-center mb-6">
                <div className="text-4xl mb-3">🪞</div>
                <h3 className="text-2xl font-bold text-white mb-4">Reflexive Verbs Quick Guide</h3>
              </div>

              <div className="text-white/90 space-y-4 mb-6">
                <p>
                  Reflexive verbs are actions you do to yourself. They use <strong className="text-purple-300">me, te, se, nous, vous, se</strong>.
                </p>

                <div className="bg-white/10 rounded-lg p-4 space-y-2">
                  <h4 className="font-semibold text-purple-200">Examples:</h4>
                  <div className="space-y-1 text-sm">
                    <div><strong className="text-blue-300">se lever</strong> → "Je me lève" (I get up)</div>
                    <div><strong className="text-blue-300">se laver</strong> → "Tu te laves" (You wash yourself)</div>
                    <div><strong className="text-blue-300">se sentir</strong> → "Elle se sent bien" (She feels good)</div>
                  </div>
                </div>

                <p className="text-sm">
                  <strong className="text-yellow-300">Pattern:</strong> The little word changes with each person (me, te, se...) but always goes before the verb.
                </p>
              </div>

              <div className="space-y-3">
                <button
                  onClick={() => handleReflexiveModalDismiss(true)}
                  className="text-sm text-blue-400 underline hover:text-blue-300 transition-colors bg-transparent border-none cursor-pointer"
                >
                  Don't remind me about reflexive verbs again
                </button>

                <button
                  onClick={() => handleReflexiveModalDismiss(false)}
                  className="w-full p-3 bg-purple-600 hover:bg-purple-700 text-white font-semibold rounded-xl transition-colors"
                >
                  Select Time Frame
                </button>
              </div>
            </div>
          </div>
        )}

        {/* Privacy Policy Footer Link */}
        <div className="fixed bottom-4 right-4">
          <Link href="/privacy">
            <button className="px-3 py-2 bg-slate-700/80 hover:bg-slate-600/80 backdrop-blur-sm border border-slate-500/50 rounded-lg text-slate-300 hover:text-white text-sm transition-colors">
              Privacy Policy
            </button>
          </Link>
        </div>
      </div>
    </div>
  );
}

export default App;

